class Solution {
public:
    vector<int> evenOddBit(int n) {
        int even = 0, odd = 0;
        while (n) {
            if (n & 1) {
                if (countBits(n) % 2 == 0) {
                    even++;
                } else {
                    odd++;
                }
            }
            n >>= 1;
        }
        return {even, odd};
    }

    int countBits(int n) {
        int count = 0;
        while (n) {
            count += n & 1;
            n >>= 1;
        }
        return count;
    }
};
```

